# Cat Behavior Simulator

class Cat:
    def __init__(self, name):
        self.name = name
        self.mood = "sleepy"
        self.hunger = 50

    def feed(self, food):
        self.hunger -= 10
        print(f"{self.name} eats")

    def pet(self):
        if self.mood == "angry":
            print("Hiss!")
        else:
            print("Purr...")

    def nap(self):
        self.mood = "sleepy"
        print(f"{self.name} naps")

    def play(self, toy):
        self.mood = "happy"
        self.hunger += 5
        print(f"Chasing {toy}!")
